export interface TradingServiceImplementation<CallContextExt = {}> {
  /** Place a new order on a prediction market. */
  createOrder(
    request: CreateOrderRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<CreateOrderResponse>>;
  /** Cancel an existing open order. */
  cancelOrder(
    request: CancelOrderRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<CancelOrderResponse>>;
  /** Cancel all open orders, optionally filtered by market. */
  cancelAllOrders(
    request: CancelAllOrdersRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<CancelAllOrdersResponse>>;
  /** Get details of a specific order. */
  getOrder(request: GetOrderRequest, context: CallContext & CallContextExt): Promise<DeepPartial<Order>>;
  /** List orders with filtering. */
  listOrders(
    request: ListOrdersRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<ListOrdersResponse>>;
  /** List executed trades with filtering. */
  listTrades(
    request: ListTradesRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<ListTradesResponse>>;
  /** Estimate order cost and fees before placement. */
  estimateOrder(
    request: EstimateOrderRequest,
    context: CallContext & CallContextExt,
  ): Promise<DeepPartial<EstimateOrderResponse>>;
}

